import React from 'react';
import { NavigationContainer } from '@react-navigation/native';
import OAuth from 'react-native-oauth';
import { Storage } from 'expo';

const CLIENT_ID = '<Your OAuth 2.0 Client ID>';
const REDIRECT_URI = '<Your Redirect URI>';
const AUTH_URL = `https://accounts.google.com/o/oauth2/v2/auth?client_id=${CLIENT_ID}&redirect_uri=${REDIRECT_URI}&response_type=code&scope=openid%20email`;

export default function App() {
  const [token, setToken] = React.useState(null);

  const handleGoogleAuth = async () => {
    try {
      const code = await OAuth.authorize(AUTH_URL);
      const response = await axios.post('https://oauth2.googleapis.com/token', {
        client_id: CLIENT_ID,
        client_secret: '<Your OAuth 2.0 Client Secret>',
        code,
        redirect_uri: REDIRECT_URI,
        grant_type: 'authorization_code'
      });

      await Storage.setItem('token', response.data.access_token);
      setToken(response.data.access_token);
    } catch (e) {
      console.log(e);
    }
  };

  const refreshAccessToken = async () => {
    try {
      const token = await Storage.getItem('token');
      const response = await axios.post('https://oauth2.googleapis.com/token', {
        client_id: CLIENT_ID,
        client_secret: '<Your OAuth 2.0 Client Secret>',
        refresh_token: token,
        grant_type: 'refresh_token'
      });

      await Storage.setItem('token', response.data.access_token);
      setToken(response.data.access_token);
    } catch (e) {
      console.log(e);
    }
  };

  React.useEffect(() => {
    const unsubscribe = navigation.addListener('focus', refreshAccessToken);
    return () => unsubscribe;
  }, []);

  if (!token) {
    return (
      <NavigationContainer>
        <Text onPress={handleGoogleAuth}>Login with Google</Text>
      </NavigationContainer>
    );
  }

  // Add your protected routes here.
}